import java.util.*;

public class Solution {

    public static List<Long> minMaxProduct(List<String> operations, List<Integer> x) {
        TreeMap<Integer, Integer> map = new TreeMap<>();
        List<Long> result = new ArrayList<>();

        for (int i = 0; i < operations.size(); i++) {
            String op = operations.get(i);
            int val = x.get(i);

            if (op.equals("push")) {
                map.put(val, map.getOrDefault(val, 0) + 1);
            } else { // pop
                int count = map.get(val);
                if (count == 1) {
                    map.remove(val);
                } else {
                    map.put(val, count - 1);
                }
            }

            int min = map.firstKey();
            int max = map.lastKey();
            result.add((long) min * max);
        }

        return result;
    }

    public static void main(String[] args) {
        // Sample Input
        List<String> operations = Arrays.asList("push", "push", "push", "pop");
        List<Integer> x = Arrays.asList(1, 2, 3, 1);

        // Method Call
        List<Long> result = minMaxProduct(operations, x);

        // Output
        System.out.println("Products: " + result);
    }
}

